    int len = array.length;
    for (int i = 0; i < len; i++) {
        for (int j = 0; j < len; j++) {
            if (array[j] > array[j+1]) {
                int temp = array[j];
                array[j] = array[j+1];
                array[j+1] = temp;
            }
        }
    }
